module RefModule(
output reg [3:0] n_ascci,
input clk,
input add_ascci,
input reset_ascci
 );reg [3:0] unused_temp;
always @(posedge clk) begin
		if (reset_ascci == 1)	unused_temp <= 4'b0000;
		else if (add_ascci == 1) unused_temp <= unused_temp+1;
			else unused_temp<=unused_temp;
		end	
always @(unused_temp) begin
		n_ascci <= unused_temp;
	end
endmodule
